   253→    public final Set<String> overriddenConfigs;
   254→
   255→    /*
   256→     * Important note: Any configuration parameter that is passed along from KafkaConfig to LogConfig
   257→     * should also be in `KafkaConfig#extractLogConfigMap`.
   258→     */
   259→    private final int segmentSize;
   260→    private final Integer internalSegmentSize;
   261→    public final long segmentMs;
   262→    public final long segmentJitterMs;
   263→    public final int maxIndexSize;
   264→    public final long flushInterval;
   265→    public final long flushMs;
   266→    public final long retentionSize;
   267→    public final long retentionMs;
   268→    public final int indexInterval;
   269→    public final long fileDeleteDelayMs;
   270→    public final long deleteRetentionMs;
   271→    public final long compactionLagMs;
   272→    public final long maxCompactionLagMs;
   273→    public final double minCleanableRatio;
   274→    public final boolean compact;
   275→    public final boolean delete;
   276→    public final boolean uncleanLeaderElectionEnable;
   277→    public final int minInSyncReplicas;
   278→    public final BrokerCompressionType compressionType;
   279→    public final Optional<Compression> compression;
   280→    public final boolean preallocate;
   281→
   282→    public final TimestampType messageTimestampType;
   283→
   284→    public final long messageTimestampBeforeMaxMs;
   285→    public final long messageTimestampAfterMaxMs;
   286→    public final List<String> leaderReplicationThrottledReplicas;
   287→    public final List<String> followerReplicationThrottledReplicas;
   288→
   289→    private final RemoteLogConfig remoteLogConfig;
   290→    private final int maxMessageSize;
   291→    private final Map<?, ?> props;
   292→
   293→    public LogConfig(Map<?, ?> props) {
   294→        this(props, Set.of());
   295→    }
   296→
   297→    @SuppressWarnings({"this-escape"})
   298→    public LogConfig(Map<?, ?> props, Set<String> overriddenConfigs) {
   299→        super(CONFIG, props, false);
   300→        this.props = Collections.unmodifiableMap(props);
   301→        this.overriddenConfigs = Collections.unmodifiableSet(overriddenConfigs);
   302→
   303→        this.segmentSize = getInt(TopicConfig.SEGMENT_BYTES_CONFIG);
   304→        this.internalSegmentSize = getInt(INTERNAL_SEGMENT_BYTES_CONFIG);
   305→        this.segmentMs = getLong(TopicConfig.SEGMENT_MS_CONFIG);
   306→        this.segmentJitterMs = getLong(TopicConfig.SEGMENT_JITTER_MS_CONFIG);
   307→        this.maxIndexSize = getInt(TopicConfig.SEGMENT_INDEX_BYTES_CONFIG);
   308→        this.flushInterval = getLong(TopicConfig.FLUSH_MESSAGES_INTERVAL_CONFIG);
   309→        this.flushMs = getLong(TopicConfig.FLUSH_MS_CONFIG);
   310→        this.retentionSize = getLong(TopicConfig.RETENTION_BYTES_CONFIG);
   311→        this.retentionMs = getLong(TopicConfig.RETENTION_MS_CONFIG);
   312→        this.maxMessageSize = getInt(TopicConfig.MAX_MESSAGE_BYTES_CONFIG);
   313→        this.indexInterval = getInt(TopicConfig.INDEX_INTERVAL_BYTES_CONFIG);
   314→        this.fileDeleteDelayMs = getLong(TopicConfig.FILE_DELETE_DELAY_MS_CONFIG);
   315→        this.deleteRetentionMs = getLong(TopicConfig.DELETE_RETENTION_MS_CONFIG);
   316→        this.compactionLagMs = getLong(TopicConfig.MIN_COMPACTION_LAG_MS_CONFIG);
   317→        this.maxCompactionLagMs = getLong(TopicConfig.MAX_COMPACTION_LAG_MS_CONFIG);
   318→        this.minCleanableRatio = getDouble(TopicConfig.MIN_CLEANABLE_DIRTY_RATIO_CONFIG);
   319→        this.compact = getList(TopicConfig.CLEANUP_POLICY_CONFIG).stream()
   320→                .map(c -> c.toLowerCase(Locale.ROOT))
   321→                .toList()
   322→                .contains(TopicConfig.CLEANUP_POLICY_COMPACT);
   323→        this.delete = getList(TopicConfig.CLEANUP_POLICY_CONFIG).stream()
   324→                .map(c -> c.toLowerCase(Locale.ROOT))
   325→                .toList()
   326→                .contains(TopicConfig.CLEANUP_POLICY_DELETE);
   327→        this.uncleanLeaderElectionEnable = getBoolean(TopicConfig.UNCLEAN_LEADER_ELECTION_ENABLE_CONFIG);
   328→        this.minInSyncReplicas = getInt(TopicConfig.MIN_IN_SYNC_REPLICAS_CONFIG);
   329→        this.compressionType = BrokerCompressionType.forName(getString(TopicConfig.COMPRESSION_TYPE_CONFIG));
   330→        this.compression = getCompression();
   331→        this.preallocate = getBoolean(TopicConfig.PREALLOCATE_CONFIG);
   332→        this.messageTimestampType = TimestampType.forName(getString(TopicConfig.MESSAGE_TIMESTAMP_TYPE_CONFIG));
   333→        this.messageTimestampBeforeMaxMs = getLong(TopicConfig.MESSAGE_TIMESTAMP_BEFORE_MAX_MS_CONFIG);
   334→        this.messageTimestampAfterMaxMs = getLong(TopicConfig.MESSAGE_TIMESTAMP_AFTER_MAX_MS_CONFIG);
   335→        this.leaderReplicationThrottledReplicas = Collections.unmodifiableList(getList(QuotaConfig.LEADER_REPLICATION_THROTTLED_REPLICAS_CONFIG));
   336→        this.followerReplicationThrottledReplicas = Collections.unmodifiableList(getList(QuotaConfig.FOLLOWER_REPLICATION_THROTTLED_REPLICAS_CONFIG));
   337→
   338→        remoteLogConfig = new RemoteLogConfig(this);
   339→    }
   340→
   341→    private Optional<Compression> getCompression() {
   342→        switch (compressionType) {
   343→            case GZIP:
   344→                return Optional.of(Compression.gzip()
   345→                        .level(getInt(TopicConfig.COMPRESSION_GZIP_LEVEL_CONFIG))
   346→                        .build());
   347→            case LZ4:
   348→                return Optional.of(Compression.lz4()
   349→                        .level(getInt(TopicConfig.COMPRESSION_LZ4_LEVEL_CONFIG))
   350→                        .build());
   351→            case ZSTD:
   352→                return Optional.of(Compression.zstd()
   353→                        .level(getInt(TopicConfig.COMPRESSION_ZSTD_LEVEL_CONFIG))
   354→                        .build());
   355→            case SNAPPY:
   356→                return Optional.of(Compression.snappy().build());
   357→            case UNCOMPRESSED:
   358→                return Optional.of(Compression.NONE);
   359→            case PRODUCER:
   360→                return Optional.empty();
   361→            default:
   362→                throw new IllegalArgumentException("Invalid value for " + TopicConfig.COMPRESSION_TYPE_CONFIG);
   363→        }
   364→    }
   365→
   366→    public int segmentSize() {
   367→        if (internalSegmentSize == null) return segmentSize;
   368→        return internalSegmentSize;
   369→    }
   370→
   371→    // Exposed as a method so it can be mocked
   372→    public int maxMessageSize() {
   373→        return maxMessageSize;
   374→    }
   375→
   376→    public long randomSegmentJitter() {
   377→        if (segmentJitterMs == 0)
   378→            return 0;
   379→        else
   380→            return Utils.abs(ThreadLocalRandom.current().nextInt()) % Math.min(segmentJitterMs, segmentMs);
   381→    }
   382→
   383→    public long maxSegmentMs() {
   384→        if (compact && maxCompactionLagMs > 0)
   385→            return Math.min(maxCompactionLagMs, segmentMs);
   386→        else
   387→            return segmentMs;
   388→    }
   389→
   390→    public int initFileSize() {
   391→        if (preallocate)
   392→            return segmentSize();
   393→        else
   394→            return 0;
   395→    }
   396→
   397→    public boolean remoteStorageEnable() {
   398→        return remoteLogConfig.remoteStorageEnable;
   399→    }
   400→
   401→    public Boolean remoteLogDeleteOnDisable() {
   402→        return remoteLogConfig.remoteLogDeleteOnDisable;
   403→    }
   404→
   405→    public Boolean remoteLogCopyDisable() {
   406→        return remoteLogConfig.remoteLogCopyDisable;
   407→    }
   408→
   409→    public long localRetentionMs() {
   410→        return remoteLogConfig.localRetentionMs == LogConfig.DEFAULT_LOCAL_RETENTION_MS ? retentionMs : remoteLogConfig.localRetentionMs;
   411→    }
   412→
   413→    public long localRetentionBytes() {
   414→        return remoteLogConfig.localRetentionBytes == LogConfig.DEFAULT_LOCAL_RETENTION_BYTES ? retentionSize : remoteLogConfig.localRetentionBytes;
   415→    }
   416→
   417→    public String overriddenConfigsAsLoggableString() {
   418→        Map<String, Object> overriddenTopicProps = new HashMap<>();
   419→        props.forEach((k, v) -> {
   420→            if (overriddenConfigs.contains(k))
   421→                overriddenTopicProps.put((String) k, v);
   422→        });
   423→        return ConfigUtils.configMapToRedactedString(overriddenTopicProps, CONFIG);
   424→    }
   425→
   426→    /**
   427→     * Create a log config instance using the given properties and defaults
   428→     */
   429→    public static LogConfig fromProps(Map<?, ?> defaults, Properties overrides) {
   430→        Properties props = new Properties();
   431→        props.putAll(defaults);
   432→        props.putAll(overrides);
   433→        Set<String> overriddenKeys = overrides.keySet().stream().map(k -> (String) k).collect(Collectors.toSet());
   434→        return new LogConfig(props, overriddenKeys);
   435→    }
   436→
   437→    // Visible for testing, return a copy since it's a mutable global variable
   438→    public static LogConfigDef configDefCopy() {
   439→        return new LogConfigDef(CONFIG);
   440→    }
   441→
   442→    public static Optional<Type> configType(String configName) {
   443→        return Optional.ofNullable(CONFIG.configKeys().get(configName)).map(c -> c.type);
   444→    }
   445→
   446→    public static List<String> configNames() {
   447→        return CONFIG.names().stream().sorted().toList();
   448→    }
   449→
   450→    public static List<String> nonInternalConfigNames() {
   451→        return CONFIG.configKeys().entrySet()
   452→                .stream()
   453→                .filter(entry -> !entry.getValue().internalConfig)
   454→                .map(Map.Entry::getKey)
   455→                .sorted().toList();
   456→    }
   457→
   458→    public static Map<String, ConfigKey> configKeys() {
   459→        return Collections.unmodifiableMap(CONFIG.configKeys());
   460→    }
   461→
   462→    /**
   463→     * Check that property names are valid
   464→     */
   465→    public static void validateNames(Properties props) {
   466→        List<String> names = configNames();
   467→        for (Object name : props.keySet())
   468→            if (!names.contains(name))
   469→                throw new InvalidConfigurationException("Unknown topic config name: " + name);
   470→    }
   471→
   472→    /**
   473→     * Validates the values of the given properties. Can be called by both client and server.
   474→     * The `props` supplied should contain all the LogConfig properties and the default values are extracted from the
   475→     * LogConfig class.
   476→     * @param props The properties to be validated
   477→     */
   478→    public static void validateValues(Map<?, ?> props) {
   479→        long minCompactionLag = (Long) props.get(TopicConfig.MIN_COMPACTION_LAG_MS_CONFIG);
   480→        long maxCompactionLag = (Long) props.get(TopicConfig.MAX_COMPACTION_LAG_MS_CONFIG);
   481→        if (minCompactionLag > maxCompactionLag) {
   482→            throw new InvalidConfigurationException("conflict topic config setting "
   483→                    + TopicConfig.MIN_COMPACTION_LAG_MS_CONFIG + " (" + minCompactionLag + ") > "
   484→                    + TopicConfig.MAX_COMPACTION_LAG_MS_CONFIG + " (" + maxCompactionLag + ")");
   485→        }
   486→    }
   487→
   488→    /**
   489→     * Validates the values of the given properties. Should be called only by the broker.
   490→     * The `props` supplied doesn't contain any topic-level configs, only broker-level configs.
   491→     * The default values should be extracted from the KafkaConfig.
   492→     * @param props The properties to be validated
   493→     */
   494→    public static void validateBrokerLogConfigValues(Map<?, ?> props,
   495→                                                     boolean isRemoteLogStorageSystemEnabled) {
   496→        validateValues(props);
   497→        if (isRemoteLogStorageSystemEnabled) {
   498→            validateRemoteStorageRetentionSize(props);
   499→            validateRemoteStorageRetentionTime(props);
   500→        }
   501→    }
   502→
   503→    /**
   504→     * Validates the values of the given properties. Should be called only by the broker.
   505→     * The `newConfigs` supplied contains the topic-level configs,
   506→     * The default values should be extracted from the KafkaConfig.
   507→     * @param existingConfigs                   The existing properties
   508→     * @param newConfigs                        The new properties to be validated
   509→     * @param isRemoteLogStorageSystemEnabled   true if system wise remote log storage is enabled
   510→     */
   511→    private static void validateTopicLogConfigValues(Map<String, String> existingConfigs,
   512→                                                     Map<?, ?> newConfigs,
   513→                                                     boolean isRemoteLogStorageSystemEnabled) {
   514→        validateValues(newConfigs);
   515→
   516→        boolean isRemoteLogStorageEnabled = (Boolean) newConfigs.get(TopicConfig.REMOTE_LOG_STORAGE_ENABLE_CONFIG);
   517→        if (isRemoteLogStorageEnabled) {
   518→            validateRemoteStorageOnlyIfSystemEnabled(newConfigs, isRemoteLogStorageSystemEnabled, false);
   519→            validateRemoteStorageRequiresDeleteCleanupPolicy(newConfigs);
   520→            validateRemoteStorageRetentionSize(newConfigs);
   521→            validateRemoteStorageRetentionTime(newConfigs);
   522→            validateRetentionConfigsWhenRemoteCopyDisabled(newConfigs, isRemoteLogStorageEnabled);
   523→        } else {
   524→            // The new config "remote.storage.enable" is false, validate if it's turning from true to false
   525→            boolean wasRemoteLogEnabled = Boolean.parseBoolean(existingConfigs.getOrDefault(TopicConfig.REMOTE_LOG_STORAGE_ENABLE_CONFIG, "false"));
   526→            validateTurningOffRemoteStorageWithDelete(newConfigs, wasRemoteLogEnabled, isRemoteLogStorageEnabled);
   527→        }
   528→    }
   529→
   530→    public static void validateTurningOffRemoteStorageWithDelete(Map<?, ?> newConfigs, boolean wasRemoteLogEnabled, boolean isRemoteLogStorageEnabled) {
   531→        boolean isRemoteLogDeleteOnDisable = (Boolean) Utils.castToStringObjectMap(newConfigs).getOrDefault(TopicConfig.REMOTE_LOG_DELETE_ON_DISABLE_CONFIG, false);
   532→        if (wasRemoteLogEnabled && !isRemoteLogStorageEnabled && !isRemoteLogDeleteOnDisable) {
   533→            throw new InvalidConfigurationException("It is invalid to disable remote storage without deleting remote data. " +
   534→                    "If you want to keep the remote data and turn to read only, please set `remote.storage.enable=true,remote.log.copy.disable=true`. " +
   535→                    "If you want to disable remote storage and delete all remote data, please set `remote.storage.enable=false,remote.log.delete.on.disable=true`.");
   536→        }
   537→    }
   538→
   539→    public static void validateRetentionConfigsWhenRemoteCopyDisabled(Map<?, ?> newConfigs, boolean isRemoteLogStorageEnabled) {
   540→        boolean isRemoteLogCopyDisabled = (Boolean) Utils.castToStringObjectMap(newConfigs).getOrDefault(TopicConfig.REMOTE_LOG_COPY_DISABLE_CONFIG, false);
   541→        long retentionMs = (Long) newConfigs.get(TopicConfig.RETENTION_MS_CONFIG);
   542→        long localRetentionMs = (Long) newConfigs.get(TopicConfig.LOCAL_LOG_RETENTION_MS_CONFIG);
   543→        long retentionBytes = (Long) newConfigs.get(TopicConfig.RETENTION_BYTES_CONFIG);
   544→        long localRetentionBytes = (Long) newConfigs.get(TopicConfig.LOCAL_LOG_RETENTION_BYTES_CONFIG);
   545→        if (isRemoteLogStorageEnabled && isRemoteLogCopyDisabled) {
   546→            if (localRetentionBytes != -2 && localRetentionBytes != retentionBytes) {
   547→                throw new InvalidConfigurationException("When `remote.log.copy.disable` is set to true, the `local.retention.bytes` " +
   548→                        "and `retention.bytes` must be set to the identical value because there will be no more logs copied to the remote storage.");
   549→            }
   550→            if (localRetentionMs != -2 && localRetentionMs != retentionMs) {
   551→                throw new InvalidConfigurationException("When `remote.log.copy.disable` is set to true, the `local.retention.ms` " +
   552→                        "and `retention.ms` must be set to the identical value because there will be no more logs copied to the remote storage.");
   553→            }
   554→        }
   555→    }
   556→
   557→    public static void validateRemoteStorageOnlyIfSystemEnabled(Map<?, ?> props, boolean isRemoteLogStorageSystemEnabled, boolean isReceivingConfigFromStore) {
   558→        boolean isRemoteLogStorageEnabled = (Boolean) props.get(TopicConfig.REMOTE_LOG_STORAGE_ENABLE_CONFIG);
   559→        if (isRemoteLogStorageEnabled && !isRemoteLogStorageSystemEnabled) {
   560→            if (isReceivingConfigFromStore) {
   561→                throw new ConfigException("You have to delete all topics with the property remote.storage.enable=true before disabling tiered storage cluster-wide");
   562→            } else {
   563→                throw new ConfigException("Tiered Storage functionality is disabled in the broker. " +
   564→                        "Topic cannot be configured with remote log storage.");
   565→            }
   566→        }
   567→    }
   568→
   569→    @SuppressWarnings("unchecked")
   570→    private static void validateRemoteStorageRequiresDeleteCleanupPolicy(Map<?, ?> props) {
   571→        List<String> cleanupPolicy = (List<String>) props.get(TopicConfig.CLEANUP_POLICY_CONFIG);
   572→        Set<String> policySet = cleanupPolicy.stream().map(policy -> policy.toLowerCase(Locale.getDefault())).collect(Collectors.toSet());
   573→        if (!Set.of(TopicConfig.CLEANUP_POLICY_DELETE).equals(policySet)) {
   574→            throw new ConfigException("Remote log storage only supports topics with cleanup.policy=delete");
   575→        }
   576→    }
   577→
   578→    private static void validateRemoteStorageRetentionSize(Map<?, ?> props) {
   579→        Long retentionBytes = (Long) props.get(TopicConfig.RETENTION_BYTES_CONFIG);
   580→        Long localRetentionBytes = (Long) props.get(TopicConfig.LOCAL_LOG_RETENTION_BYTES_CONFIG);
   581→        if (retentionBytes > -1 && localRetentionBytes != -2) {
   582→            if (localRetentionBytes == -1) {
   583→                String message = String.format("Value must not be -1 as %s value is set as %d.",
   584→                        TopicConfig.RETENTION_BYTES_CONFIG, retentionBytes);
   585→                throw new ConfigException(TopicConfig.LOCAL_LOG_RETENTION_BYTES_CONFIG, localRetentionBytes, message);
   586→            }
   587→            if (localRetentionBytes > retentionBytes) {
   588→                String message = String.format("Value must not be more than %s property value: %d",
   589→                        TopicConfig.RETENTION_BYTES_CONFIG, retentionBytes);
   590→                throw new ConfigException(TopicConfig.LOCAL_LOG_RETENTION_BYTES_CONFIG, localRetentionBytes, message);
   591→            }
   592→        }
   593→    }
   594→
   595→    private static void validateRemoteStorageRetentionTime(Map<?, ?> props) {
   596→        Long retentionMs = (Long) props.get(TopicConfig.RETENTION_MS_CONFIG);
   597→        Long localRetentionMs = (Long) props.get(TopicConfig.LOCAL_LOG_RETENTION_MS_CONFIG);
   598→        if (retentionMs != -1 && localRetentionMs != -2) {
   599→            if (localRetentionMs == -1) {
   600→                String message = String.format("Value must not be -1 as %s value is set as %d.",
   601→                        TopicConfig.RETENTION_MS_CONFIG, retentionMs);
   602→                throw new ConfigException(TopicConfig.LOCAL_LOG_RETENTION_MS_CONFIG, localRetentionMs, message);
   603→            }
   604→            if (localRetentionMs > retentionMs) {
   605→                String message = String.format("Value must not be more than %s property value: %d",
   606→                        TopicConfig.RETENTION_MS_CONFIG, retentionMs);
   607→                throw new ConfigException(TopicConfig.LOCAL_LOG_RETENTION_MS_CONFIG, localRetentionMs, message);
   608→            }
   609→        }
   610→    }
   611→
   612→    /**
   613→     * Check that the given properties contain only valid log config names and that all values can be parsed and are valid
   614→     */
   615→    public static void validate(Properties props) {
   616→        validate(Map.of(), props, Map.of(), false);
   617→    }
   618→
   619→    public static void validate(Map<String, String> existingConfigs,
   620→                                Properties props,
   621→                                Map<?, ?> configuredProps,
   622→                                boolean isRemoteLogStorageSystemEnabled) {
   623→        validateNames(props);
   624→        if (configuredProps == null || configuredProps.isEmpty()) {
   625→            Map<?, ?> valueMaps = CONFIG.parse(props);
   626→            validateValues(valueMaps);
   627→        } else {
   628→            Map<Object, Object> combinedConfigs = new HashMap<>(configuredProps);
   629→            combinedConfigs.putAll(props);
   630→            Map<?, ?> valueMaps = CONFIG.parse(combinedConfigs);
   631→            validateTopicLogConfigValues(existingConfigs, valueMaps, isRemoteLogStorageSystemEnabled);
   632→        }
   633→    }
   634→
   635→    @Override
