   637→        return "LogConfig{" +
   638→                "segmentSize=" + segmentSize() +
   639→                ", segmentMs=" + segmentMs +
   640→                ", segmentJitterMs=" + segmentJitterMs +
   641→                ", maxIndexSize=" + maxIndexSize +
   642→                ", flushInterval=" + flushInterval +
   643→                ", flushMs=" + flushMs +
   644→                ", retentionSize=" + retentionSize +
   645→                ", retentionMs=" + retentionMs +
   646→                ", indexInterval=" + indexInterval +
   647→                ", fileDeleteDelayMs=" + fileDeleteDelayMs +
   648→                ", deleteRetentionMs=" + deleteRetentionMs +
   649→                ", compactionLagMs=" + compactionLagMs +
   650→                ", maxCompactionLagMs=" + maxCompactionLagMs +
   651→                ", minCleanableRatio=" + minCleanableRatio +
   652→                ", compact=" + compact +
   653→                ", delete=" + delete +
   654→                ", uncleanLeaderElectionEnable=" + uncleanLeaderElectionEnable +
   655→                ", minInSyncReplicas=" + minInSyncReplicas +
   656→                ", compressionType='" + compressionType + '\'' +
   657→                ", preallocate=" + preallocate +
   658→                ", messageTimestampType=" + messageTimestampType +
   659→                ", leaderReplicationThrottledReplicas=" + leaderReplicationThrottledReplicas +
   660→                ", followerReplicationThrottledReplicas=" + followerReplicationThrottledReplicas +
   661→                ", remoteLogConfig=" + remoteLogConfig +
   662→                ", maxMessageSize=" + maxMessageSize +
   663→                '}';
   664→    }
